import{_ as t,o,c as a,ae as n}from"./chunks/framework.BWBVoeBT.js";const i="/linux-notes/assets/20251017011812.C2QzWfYm.png",g=JSON.parse('{"title":"Tips & Tricks","description":"","frontmatter":{},"headers":[],"relativePath":"notes/tips-tricks.md","filePath":"notes/tips-tricks.md"}'),s={name:"notes/tips-tricks.md"};function d(r,e,c,l,p,h){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="tips-tricks" tabindex="-1">Tips &amp; Tricks <a class="header-anchor" href="#tips-tricks" aria-label="Permalink to &quot;Tips &amp; Tricks&quot;">​</a></h1><h2 id="move-and-resize-windows-quickly" tabindex="-1">Move and Resize Windows Quickly <a class="header-anchor" href="#move-and-resize-windows-quickly" aria-label="Permalink to &quot;Move and Resize Windows Quickly&quot;">​</a></h2><p>Go to <code>System Settings</code> -&gt; <code>Apps &amp; Windows</code> -&gt; <code>Window Management</code> -&gt; <code>Window Behavior</code> -&gt; <code>Window Actions</code>.</p><ul><li>Meta + left-drag: move the window</li><li>Meta + right-drag: resize the window</li></ul><h2 id="start-apps-automatically-at-login" tabindex="-1">Start Apps Automatically at Login <a class="header-anchor" href="#start-apps-automatically-at-login" aria-label="Permalink to &quot;Start Apps Automatically at Login&quot;">​</a></h2><p>Add the app under <code>System Settings</code> -&gt; <code>System</code> -&gt; <code>Autostart</code>.</p><p><img src="'+i+'" alt=""></p><h2 id="turn-off-unneeded-desktop-effects" tabindex="-1">Turn Off Unneeded Desktop Effects <a class="header-anchor" href="#turn-off-unneeded-desktop-effects" aria-label="Permalink to &quot;Turn Off Unneeded Desktop Effects&quot;">​</a></h2><p>Go to <code>System Settings</code> -&gt; <code>Apps &amp; Windows</code> -&gt; <code>Window Management</code> -&gt; <code>Desktop Effects</code>, and disable the effects you do not need.</p><p>I only keep these enabled:</p><ul><li><strong>Dim Inactive Windows</strong>: reduce the color saturation of unresponsive or frozen windows</li><li><strong>Highlight Screen Edge</strong>: highlight screen edges and corners when the pointer reaches an active trigger area</li><li><strong>Dim Parent Windows</strong>: dim the parent window of the currently active dialog</li><li><strong>Desktop Grid</strong>: show an overview of virtual desktops and windows, and activate it with a shortcut</li></ul><h2 id="open-dolphin-folders-in-tabs-instead-of-new-windows" tabindex="-1">Open Dolphin Folders in Tabs Instead of New Windows <a class="header-anchor" href="#open-dolphin-folders-in-tabs-instead-of-new-windows" aria-label="Permalink to &quot;Open Dolphin Folders in Tabs Instead of New Windows&quot;">​</a></h2><p>In <code>Dolphin</code>, click the icon at the far right of the address bar, then go to <code>Configure</code> -&gt; <code>Configure Dolphin</code> -&gt; <code>Interface</code> -&gt; <code>Folders &amp; Tabs</code> -&gt; <code>Opening Folders</code>, and enable <code>Open new folders in tabs</code>.</p>',13)])])}const u=t(s,[["render",d]]);export{g as __pageData,u as default};
